                // 5. Assets Created
                if (data.assets && data.assets.length) {
                    html += `
                        <div class="detail-section">
                            <div class="detail-title">Assets Created</div>
                            <div style="display: grid; grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); gap: 12px;">
